/*
 * expm1() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly expm1  (test_expm1_opt.elf)
 *   2. Linked with toolchain's default expm1       (test_expm1_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += expm1(vx);
#else
    double r = expm1(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);                                   /* expm1(+0) = +0 */
    emit(-0.0);                                  /* expm1(-0) = -0 */
    emit_u(0x7ff8000000000000ULL);               /* qNaN */
    emit_u(0x7ff0000000000001ULL);               /* sNaN */
    emit_u(0xfff8000000000000ULL);               /* -qNaN */
    emit_u(0x7ff0000000000000ULL);               /* +Inf: expm1(+Inf) = +Inf */
    emit_u(0xfff0000000000000ULL);               /* -Inf: expm1(-Inf) = -1 */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);               /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);               /* min negative subnormal */
    emit_u(0x0008000000000000ULL);               /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);               /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);               /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);               /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(DBL_MIN);                               /* 2^-1022: smallest normal */
    emit(-DBL_MIN);                              /* -2^-1022 */
    emit_u(0x0010000000000001ULL);               /* one ULP above DBL_MIN */
    emit_u(0x7fefffffffffffffULL);               /* DBL_MAX: largest finite double */
    emit_u(0xffefffffffffffffULL);               /* -DBL_MAX */
    emit_u(0x7feffffffffffff0ULL);               /* a few ULPs below DBL_MAX */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3fefffffffffffffULL);               /* one ULP below 1.0 */
    emit(1.0);                                   /* expm1(1) = e-1 */
    emit_u(0x3ff0000000000001ULL);               /* one ULP above 1.0 */
    emit_u(0x3feffffffff00000ULL);               /* a few ULPs below 1.0 */
    emit_u(0x3ff0000000100000ULL);               /* a few ULPs above 1.0 */
    emit(-1.0);                                  /* expm1(-1) = 1/e - 1 ~ -0.632 */
    emit_u(0xbfefffffffffffffULL);               /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);               /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3fe0000000000000ULL);               /* 0.5 */
    emit_u(0x3fdffffffffffffeULL);               /* one ULP below 0.5 */
    emit_u(0x3fe0000000000001ULL);               /* one ULP above 0.5 */
    emit_u(0x4000000000000000ULL);               /* 2.0 */
    emit_u(0x3fffffffffffffffULL);               /* one ULP below 2.0 */
    emit_u(0x4000000000000001ULL);               /* one ULP above 2.0 */

    /* --- Section 6: Mathematical constants for expm1 (14) --- */
    emit_u(0x3fe62e42fefa39efULL);               /* ln2: expm1(ln2) = 1.0 exactly */
    emit_u(0xbfe62e42fefa39efULL);               /* -ln2: expm1(-ln2) = -0.5 */
    emit_u(0x3fe62e42fefa39f0ULL);               /* one ULP above ln2 */
    emit_u(0x3fe62e42fefa39eeULL);               /* one ULP below ln2 */
    emit(0.5);                                   /* expm1(0.5) = sqrt(e)-1 */
    emit(-0.5);                                  /* expm1(-0.5) */
    emit(2.0);                                   /* expm1(2) = e^2 - 1 */
    emit(-2.0);                                  /* expm1(-2) */
    emit(10.0);                                  /* large positive result */
    emit(-10.0);                                 /* approaches -1 from above */
    emit_u(0x4005bf0a8b145769ULL);               /* ln(10): expm1(ln10) = 9 */
    emit_u(0x4000000000000000ULL);               /* 2.0: expm1(2) = e^2-1 (dup check vs Sec5) */
    emit(0.6931471805599453);                    /* ln2 as decimal */
    emit(-0.6931471805599453);                   /* -ln2 as decimal */

    /* --- Section 7: Overflow/underflow threshold values (8) --- */
    emit_u(0x40862e42fefa39efULL);               /* exp overflow threshold ~709.78 */
    emit_u(0x40862e42fefa39f0ULL);               /* one ULP above overflow threshold */
    emit_u(0x40862e42fefa39eeULL);               /* one ULP below overflow threshold */
    emit(708.0);                                 /* just below overflow */
    emit(709.0);                                 /* at overflow boundary */
    emit(1000.0);                                /* deep overflow */
    emit(-745.0);                                /* near underflow: expm1 -> -1 */
    emit(-746.0);                                /* past underflow threshold */

    /* --- Section 8: Near-zero Taylor series path (15) --- */
    /* expm1(x) ~ x + x^2/2 + ... for small x; accuracy critical here */
    emit(1.0e-20);                               /* expm1 ~ x */
    emit(-1.0e-20);
    emit(1.0e-15);                               /* approaching representable error */
    emit(-1.0e-15);
    emit(1.0e-10);                               /* small but not tiny */
    emit(-1.0e-10);
    emit(1.0e-7);                                /* threshold where x^2/2 becomes relevant */
    emit(-1.0e-7);
    emit(1.0e-5);                                /* quadratic term starts to matter */
    emit(-1.0e-5);
    emit_u(0x3e50000000000000ULL);               /* 2^-26: typical Taylor switch boundary */
    emit_u(0xbe50000000000000ULL);               /* -2^-26 */
    emit_u(0x3c90000000000000ULL);               /* 2^-54: near machine epsilon */
    emit_u(0xbc90000000000000ULL);               /* -2^-54 */
    emit(5.0e-324);                              /* smallest positive double (min subnormal decimal) */

    /* --- Section 9: Fast-path / branch threshold values (8) --- */
    /* Many expm1 implementations switch algorithms at powers of 2 */
    emit_u(0x3fb0000000000000ULL);               /* 2^-4 = 0.0625: often a polynomial threshold */
    emit_u(0xbfb0000000000000ULL);               /* -2^-4 */
    emit_u(0x3fc0000000000000ULL);               /* 2^-3 = 0.125 */
    emit_u(0xbfc0000000000000ULL);               /* -2^-3 */
    emit_u(0x3fd0000000000000ULL);               /* 0.25: another common branch point */
    emit_u(0xbfd0000000000000ULL);               /* -0.25 */
    emit_u(0x3ff7154765200000ULL);               /* log(2)*3/2 ~ 1.04: near exp reduction boundary */
    emit_u(0xbff7154765200000ULL);               /* negative version */

    /* --- Section 10: Hard cases and polynomial branch stress (22) --- */
    /* Values that stress intermediate polynomial paths and argument reduction */
    emit(-100.0);                                /* deep negative: result ~= -1 */
    emit(-50.0);                                 /* still near -1 */
    emit(-20.0);                                 /* result = e^-20 - 1 ~ -1 */
    emit(100.0);                                 /* large: result ~ e^100 */
    emit(50.0);                                  /* moderate large */
    emit(20.0);                                  /* result = e^20 - 1 */
    emit(0.1);                                   /* inside main polynomial range */
    emit(-0.1);
    emit(0.01);                                  /* smaller argument */
    emit(-0.01);
    emit(0.001);                                 /* near the Taylor series regime */
    emit(-0.001);
    emit_u(0x3fe921fb54442d18ULL);               /* pi/4 ~ 0.785: mid polynomial range */
    emit_u(0xbfe921fb54442d18ULL);               /* -pi/4 */
    emit_u(0x3ff921fb54442d18ULL);               /* pi/2 ~ 1.571: near ln2*2 */
    emit_u(0xbff921fb54442d18ULL);               /* -pi/2 */
    emit_u(0x400921fb54442d18ULL);               /* pi ~ 3.14159 */
    emit_u(0xc00921fb54442d18ULL);               /* -pi */
    emit(3.0);                                   /* moderate positive */
    emit(-3.0);                                  /* moderate negative */
    emit(5.0);                                   /* larger positive */
    emit(-5.0);                                  /* larger negative */
}

/* ------------------------------------------------------------------ */

/* 7. Sweep [-100, 100] in 200 steps */
#ifndef EN_PERF
static void test_sweep(void)
{
    double hi = 100.0;
    int nsteps = 200;
    double step = (2.0 * hi) / (double)nsteps;

    /* [-100, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);

    /* [0, 100] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);
}

/* 8. Sample [0, 0.1] at a few representative bit patterns */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3f847ae147ae147bULL, /* 0.01 */
        0x3f9eb851eb851eb8ULL, /* 0.03 */
        0x3fa999999999999aULL, /* 0.05 */
        0x3fb4cccccccccccdULL, /* 0.08 */
        0x3fb999999999999aULL, /* ~0.1 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i]);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}
